import logging
import time

from workflows.engine import engine

# Import all workflows to register them
import workflows.wf_auto_generate_on_calibration_done  # noqa: F401

logger = logging.getLogger("workflow.scheduler")

SCHEDULED_WORKFLOWS = [

]


def run_scheduled():
    """Run all scheduled workflows (integrate with your cron/schedule library)."""
    for name, cron in SCHEDULED_WORKFLOWS:
        logger.info(f"Running scheduled workflow: {name} ({cron})")
        try:
            result = engine.run(name)
            logger.info(f"  Result: {result.status.value}")
        except Exception as e:
            logger.error(f"  Error: {e}")


if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)
    run_scheduled()
